// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract StreamStake is Ownable {
    // Basic types
    enum Side { NONE, BLUE, RED }
    enum Status { ACTIVE, RESOLVED, CANCELLED }

    struct RoundBroadCast {
        string roundId;
        uint256 totalPoolBlue;
        uint256 totalPoolRed;
        Status status;
        Side winner;
    }

    struct Props {
        uint256 totalPoolBlue;
        uint256 totalPoolRed;
        Status status;
        Side winner;
        bool exists;
        mapping(address => uint256) betsBlue;
        mapping(address => uint256) betsRed;
    }

    // Lobby -> RoundId -> Props
    mapping(string => mapping(string => Props)) public lobbies;
    
    // Oracle Address (The Backend)
    address public oracle;

    // Events
    event BetPlaced(string lobbyId, string roundId, address indexed user, Side side, uint256 amount);
    event RoundResolved(string lobbyId, string roundId, Side winner, uint256 totalPool);
    event WinningsClaimed(string lobbyId, string roundId, address indexed user, uint256 amount);

    constructor() Ownable(msg.sender) {
        oracle = msg.sender;
    }

    modifier onlyOracle() {
        require(msg.sender == oracle || msg.sender == owner(), "Not Oracle");
        _;
    }

    // --- Core Logic ---

    function placeBet(string calldata lobbyId, string calldata roundId, Side side) external payable {
        require(msg.value > 0, "Bet amount must be > 0");
        require(side != Side.NONE, "Invalid side");
        
        Props storage round = lobbies[lobbyId][roundId];
        
        // If first bet, init round
        if (!round.exists) {
            round.exists = true;
            round.status = Status.ACTIVE;
        }

        require(round.status == Status.ACTIVE, "Round not active");

        if (side == Side.BLUE) {
            round.betsBlue[msg.sender] += msg.value;
            round.totalPoolBlue += msg.value;
        } else {
            round.betsRed[msg.sender] += msg.value;
            round.totalPoolRed += msg.value;
        }

        emit BetPlaced(lobbyId, roundId, msg.sender, side, msg.value);
    }

    function resolveRound(string calldata lobbyId, string calldata roundId, Side winner) external onlyOracle {
        Props storage round = lobbies[lobbyId][roundId];
        require(round.exists, "Round does not exist");
        require(round.status == Status.ACTIVE, "Round already resolved");

        round.winner = winner;
        round.status = Status.RESOLVED;

        emit RoundResolved(lobbyId, roundId, winner, round.totalPoolBlue + round.totalPoolRed);
    }

    function claimWinnings(string calldata lobbyId, string calldata roundId) external {
        Props storage round = lobbies[lobbyId][roundId];
        require(round.status == Status.RESOLVED, "Round not resolved");

        uint256 reward = 0;
        uint256 userBet = 0;
        uint256 winningPool = 0;
        uint256 losingPool = 0;

        if (round.winner == Side.BLUE) {
            userBet = round.betsBlue[msg.sender];
            winningPool = round.totalPoolBlue;
            losingPool = round.totalPoolRed;
            // Reset to prevent double claim
            round.betsBlue[msg.sender] = 0;
        } else if (round.winner == Side.RED) {
            userBet = round.betsRed[msg.sender];
            winningPool = round.totalPoolRed;
            losingPool = round.totalPoolBlue;
            // Reset
            round.betsRed[msg.sender] = 0;
        } else {
            revert("Invalid winner state");
        }

        require(userBet > 0, "No winnings to claim");

        // Calculate Share: (UserBet / WinningPool) * (WinningPool + LosingPool)
        // Simplified: UserBet + (UserBet * LosingPool / WinningPool)
        // Note: Basic implementation, ignores precision loss for now.
        // reward = userBet + (userBet * losingPool) / winningPool; 
        
        // Safer Calc: (UserBet * TotalPool) / WinningPool
        if (winningPool > 0) {
            uint256 totalPool = winningPool + losingPool;
            reward = (userBet * totalPool) / winningPool;
        } else {
            // Should not happen if winner declared and userBet > 0
            reward = userBet; 
        }

        (bool sent, ) = payable(msg.sender).call{value: reward}("");
        require(sent, "Failed to send Ether");

        emit WinningsClaimed(lobbyId, roundId, msg.sender, reward);
    }
    
    // View Functions
    function getRoundPools(string calldata lobbyId, string calldata roundId) external view returns (uint256 blue, uint256 red, Status status) {
        Props storage round = lobbies[lobbyId][roundId];
        return (round.totalPoolBlue, round.totalPoolRed, round.status);
    }
}

